// Calculate marking statistics
const items = $input.all();

if (items.length === 0) {
  return [{ json: { error: 'No items to process' } }];
}

// Extract marks data
const marksData = items.map(item => {
  const marksAwarded = item.json.marksAwarded || 0;
  const totalMarksAvailable = item.json.totalMarksAvailable || 100;
  const percentage = item.json.percentage || 0;
  const grade = item.json.grade || 'N/A';

  return {
    marksAwarded,
    totalMarksAvailable,
    percentage,
    grade
  };
});

// Calculate average marks
const totalMarks = marksData.reduce((sum, item) => sum + item.marksAwarded, 0);
const averageMarks = totalMarks / marksData.length;

// Calculate average percentage
const totalPercentage = marksData.reduce((sum, item) => sum + item.percentage, 0);
const averagePercentage = totalPercentage / marksData.length;

// Calculate standard deviation
const squaredDifferences = marksData.map(item => Math.pow(item.marksAwarded - averageMarks, 2));
const variance = squaredDifferences.reduce((sum, val) => sum + val, 0) / marksData.length;
const standardDeviation = Math.sqrt(variance);

// Calculate grade distribution
const gradeDistribution = marksData.reduce((acc, item) => {
  const grade = item.grade;
  acc[grade] = (acc[grade] || 0) + 1;
  return acc;
}, {});

// Calculate pass/fail counts
const passCount = marksData.filter(item => item.grade === 'PASS').length;
const failCount = marksData.filter(item => item.grade === 'FAIL').length;
const passRate = (passCount / marksData.length) * 100;

// Find min and max marks
const allMarks = marksData.map(item => item.marksAwarded);
const minMarks = Math.min(...allMarks);
const maxMarks = Math.max(...allMarks);

// Calculate median
const sortedMarks = [...allMarks].sort((a, b) => a - b);
const median = sortedMarks.length % 2 === 0
  ? (sortedMarks[sortedMarks.length / 2 - 1] + sortedMarks[sortedMarks.length / 2]) / 2
  : sortedMarks[Math.floor(sortedMarks.length / 2)];

// Return statistics
return [{
  json: {
    totalStudents: marksData.length,
    averageMarks: Math.round(averageMarks * 100) / 100,
    averagePercentage: Math.round(averagePercentage * 100) / 100,
    standardDeviation: Math.round(standardDeviation * 100) / 100,
    median: Math.round(median * 100) / 100,
    minMarks,
    maxMarks,
    passCount,
    failCount,
    passRate: Math.round(passRate * 100) / 100,
    gradeDistribution,
    calculatedAt: new Date().toISOString()
  }
}];

